class Solution(object):
    def minDeletions(self, s, queries):
        """
        :type s: str
        :type queries: List[List[int]]
        :rtype: List[int]
        """
        n = len(s)

        # Fenwick Tree for efficient range queries and updates
        class FenwickTree:
            def __init__(self, size):
                self.size = size
                self.tree = [0] * (size + 1)

            def update(self, i, delta):
                i += 1  # Convert to 1-indexed
                while i <= self.size:
                    self.tree[i] += delta
                    i += i & (-i)

            def query(self, i):
                if i < 0:
                    return 0
                i += 1  # Convert to 1-indexed
                result = 0
                while i > 0:
                    result += self.tree[i]
                    i -= i & (-i)
                return result

            def range_query(self, l, r):
                if l > r:
                    return 0
                return self.query(r) - (self.query(l - 1) if l > 0 else 0)

        # eq[i] = 1 if s[i] == s[i-1], else 0
        eq = [0] * n
        for i in range(1, n):
            eq[i] = 1 if s[i] == s[i-1] else 0

        fenwick = FenwickTree(n)
        for i in range(1, n):
            fenwick.update(i, eq[i])

        results = []
        s_list = list(s)

        for query in queries:
            if query[0] == 1:
                # Flip operation
                j = query[1]
                # Flip the character
                s_list[j] = 'B' if s_list[j] == 'A' else 'A'

                # Update eq[j] if j > 0
                if j > 0:
                    old_eq = eq[j]
                    new_eq = 1 if s_list[j] == s_list[j-1] else 0
                    if old_eq != new_eq:
                        fenwick.update(j, new_eq - old_eq)
                        eq[j] = new_eq

                # Update eq[j+1] if j+1 < n
                if j + 1 < n:
                    old_eq = eq[j + 1]
                    new_eq = 1 if s_list[j+1] == s_list[j] else 0
                    if old_eq != new_eq:
                        fenwick.update(j + 1, new_eq - old_eq)
                        eq[j + 1] = new_eq

            else:
                # Query operation
                l, r = query[1], query[2]
                # Count equal adjacent pairs in range [l, r]
                # This is sum of eq[l+1..r]
                if l < r:
                    result = fenwick.range_query(l + 1, r)
                else:
                    result = 0
                results.append(result)

        return results
